> **- Tegan Hurst (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/blue-turtle-beach-1.jpg','099 279 9073','119, 1, Tambon Bo Put, Amphoe Ko Samui, Chang Wat Surat Thani 84320, Thailand',NULL,NULL,4.6,0,0,0,NULL,'https://www.blueturtlehotelsamui.com/',NULL,'cmr07ifv6001cq8xd5vsyfm44','cmr07ifuw0018q8xd0skvb1rt','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:11.207+00:00','2026-06-30T05:29:11.207+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/blue-turtle-beach-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/blue-turtle-beach-2.jpg"]','https://maps.google.com/?cid=13778516509879075039',NULL,NULL);
INSERT INTO "Listing" VALUES('blue-voyage-yachting','standard','cmr07ig4p004sq8xdvyf1swfk','Blue Voyage Yachting','## Top Reviews
> "A great day out with family in end February. The Blue Coco is a beautiful catamaran. The captain and crew were very good and made our trip memorable. The fruit salad was delicious. Remember to take alcohol with you."
