INSERT INTO "Listing" VALUES('boots-pharmacy','standard','cmr07ig55004zq8xdxowxbhyp','Boots Pharmacy','## Top Reviews
> "Not too much people here... have free parking"
> **- suki tse (5/5/5)**

> "More for cosmetics and lotions/ vitamins, than a pharmacy..."
> **- Jim P (3/5/5)**

> "The number of shops was somewhat disappointing. However, there was one large store with a wide variety of items (supermarket + clothing + suitcases + decorations, etc.).  The restrooms weren''t very clean, and there was no toilet paper.  The stalls seemed quite expensive in comparison."
