INSERT INTO "Listing" VALUES('chais-cuisine-farm','standard','cmr07ig7u0065q8xddsvkag8m','Chai''s Cuisine & Farm','## Top Reviews
> "An Absolute Hidden Gem in Koh Samui – A Must-Visit! If you are on the island, you absolutely must visit this place. It is a unique, organic farm-to-table experience where the chef cooks right in front of you while you wait. The menu is packed with delicious seafood and meat dishes, with many of the fresh ingredients coming straight from the farm itself. Everything is prepared live and executed to absolute perfection. Beyond the incredible food, the chef is a fantastic host. He is wonderful to talk to, full of great conversation, and made our day so memorable. We enjoyed every single moment and every single bite. Do yourself a favor and book a spot here—it’s an unforgettable island experience! 🌿🥩🐟✨"
> **- Aleksandra Grajczyk (5/5/5)**

> "This is a must do if you visit Samui.  Yes, it’s out of the way but well worth the visit.  The food is cooked by Chai and Rhut and the vegetables are sourced from the farm which is around you.  There is no menu as such and you will agree with him before what you would like to eat.  His signature dish is the Massaman curry although his kaprow is also delicious too.  This is not a rock up and dine restaurant, you need to pre book with Chai!"
> **- Dozza Ko (5/5/5)**

> "A slice of heaven ✨️ a magical evening filled with laughter and love. Chai''s remarkable tasty dishes were a total joy to experience. An evening I will remember for a long time."
> **- Paula Harrowing (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chais-cuisine-farm-1.jpg','080 532 9005','58/11, ตำบล หน้าเมือง อำเภอเกาะสมุย สุราษฎร์ธานี 84310, Thailand',NULL,NULL,4.8,0,0,0,NULL,'https://www.facebook.com/Chais-Cuisine-Farm-658723690876303/','["Monday: Closed","Tuesday: 9:30 AM – 10:00 PM","Wednesday: 9:30 AM – 10:00 PM","Thursday: 9:30 AM – 10:00 PM","Friday: 9:30 AM – 10:00 PM","Saturday: 9:30 AM – 10:00 PM","Sunday: 9:30 AM – 10:00 PM"]','cmr07ifpj0000q8xdet31f7qd','cmr07ig4i004oq8xdv207xuh2','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:11.322+00:00','2026-06-30T05:29:11.322+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chais-cuisine-farm-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chais-cuisine-farm-2.jpg"]','https://maps.google.com/?cid=13773340506330317742',NULL,NULL);
