INSERT INTO "Listing" VALUES('chilli-restaurant','standard','cmr07ig9v006xq8xdn563cxq8','Chilli Restaurant','## Top Reviews
> "Incredible food, fresh and well cooked, very friendly and welcoming service and good vibes among the team. We came multiple times during our 2 week stay. Was our favorite Restaurant in chaweng!"
> **- Carmen (5/5/5)**

> "The food was absolutely delicious, and the staff were very kind and professional. They were happy to adjust the dishes to our needs. We had steaks, steamed fish, and of course a few traditional dishes – everything was super tasty. Highly recommended, and we’ll definitely come back!"
> **- Anna Simonov (5/5/5)**

> "The best tom kha gai I tasted after being here for 1 week The Thai fried rice was also very delicious! It was really creamy I love that. They gave me without seasoning it with vinegar and spice and gave me some spices to add it by myself. Which is wonderful bc I tried somewhere else with heavy seasoning and I didn''t like that. It''s nice that they let us to adjust by ourselves! The Thai fried rice tastes very THAI! Love it. Not too strong and salty. Which is also a plus♥️ Lovely restaurant I''ll totally go again for Thai food!!! Also, the shrimp was very fresh!!! Staffs are friendly and nice, manager was doing a good job too. The tiny problem is the drink wasn''t too good🥲Smoothie not cold enough and juice was very normal."
> **- うる (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chilli-restaurant-1.jpg','080 434 3197','Chaweng 167/69 T.bon, ตำบล บ่อผุด อำเภอเกาะสมุย สุราษฎร์ธานี 84320, Thailand',NULL,NULL,4.6,0,0,0,NULL,'https://www.chilli-restaurant.com/','["Monday: 11:00 AM – 12:00 AM","Tuesday: 11:00 AM – 12:00 AM","Wednesday: 11:00 AM – 12:00 AM","Thursday: 11:00 AM – 12:00 AM","Friday: 11:00 AM – 12:00 AM","Saturday: 11:00 AM – 12:00 AM","Sunday: 11:00 AM – 12:00 AM"]','cmr07ifpj0000q8xdet31f7qd','cmr07ifuw0018q8xd0skvb1rt','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:11.395+00:00','2026-06-30T05:29:11.395+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chilli-restaurant-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chilli-restaurant-2.jpg"]','https://maps.google.com/?cid=9948552009160436362',NULL,NULL);
INSERT INTO "Listing" VALUES('chiva-sai-spa','standard','cmr07ig9x006yq8xdq3tejf1w','Chiva Sai Spa','## Top Reviews
> "We came here in the evening for a foot massage. It was far too noisy — people were talking loudly, children were playing with plastic bags and nobody said anything for over 20 minutes. Relaxation was impossible.  The massage itself felt more like gentle stroking. We ended up leaving after 25 minutes because of the noise. Disappointing."
> **- Fabi (1/5/5)**

> "Would not recommend getting a manicure here. They were very kind and sweet while getting our nails done (aside from her causing me to bleed on several fingers)… But afterwards we experienced terrible customer service. We had gel nails done on Friday, and by Sunday my nail had already started chipping off and the polish on my partners nails was bubbling up, probably due to not being cured properly. We went back in and politely showed them what was wrong and requested that they remedy the problem and they refused to give us any sort of compensation. We spoke with the manager Noy over the phone and she was very rude and ended up hanging up on us."
> **- Janni & Korbyn (1/5/5)**

> "My go-to for serious sports massage, scrubs, aloe, etc. Nice to use the steam room first. Very professional shop. Easy parking in the back which is more convenient for driving usually."
> **- Muffy M (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chiva-sai-spa-1.jpg','092 254 2876','Bo Put, Ko Samui District, Surat Thani 84320, Thailand',NULL,NULL,4.2,0,0,0,NULL,'https://www.facebook.com/102632624442725/','["Monday: 11:00 AM – 12:00 AM","Tuesday: 11:00 AM – 12:00 AM","Wednesday: 11:00 AM – 12:00 AM","Thursday: 11:00 AM – 12:00 AM","Friday: 11:00 AM – 12:00 AM","Saturday: 11:00 AM – 12:00 AM","Sunday: 11:00 AM – 12:00 AM"]','cmr07ifst000mq8xdudn7dwk1','cmr07ig5c0051q8xdykrbexft','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:11.397+00:00','2026-06-30T05:29:11.397+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chiva-sai-spa-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/chiva-sai-spa-2.jpg"]','https://maps.google.com/?cid=4727224283624778343',NULL,NULL);
