INSERT INTO "Listing" VALUES('curry-hut','standard','cmr07igca007xq8xdtveqqk8f','Curry Hut','## Top Reviews
> "Had a fantastic experience at Curry Hut Indian Restaurant in Koh Samui! The food tasted absolutely authentic—just like home. The curries were rich and flavorful, naan was soft and fresh, and the spices were perfectly balanced.  The staff was very welcoming and made sure everything was served hot and quickly. The restaurant has a clean, cozy vibe, and the pricing is reasonable for the quality you get.  If you’re craving real Indian food in Koh Samui, Curry Hut is a must-visit! Highly recommended for families, couples, and anyone who loves delicious Indian cuisine."
> **- Akshay Shrivastav (5/5/5)**

> "Amazing. The food was delish and just the right “heat”. Atmosphere great and service spectacular. We will be back! The set for two was great value for money and so scrumptious"
> **- Lisa Giltrow (5/5/5)**

> "one of the best indiant I ever eat in chaweng! they have been here for a very long time, and the quality is very top!  I recommend !"
> **- tony samui (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/curry-hut-1.jpg','098 510 2416','167 18 Chaweng Beach Rd, Tambon Bo Put, Amphoe Ko Samui, Chang Wat Surat Thani 84320, Thailand',NULL,NULL,4.5,0,0,0,NULL,'https://curryhutindian.com/','["Monday: 11:00 AM – 11:30 PM","Tuesday: 11:00 AM – 11:30 PM","Wednesday: 11:00 AM – 11:30 PM","Thursday: 11:00 AM – 11:30 PM","Friday: 11:00 AM – 11:30 PM","Saturday: 11:00 AM – 11:30 PM","Sunday: 11:00 AM – 11:30 PM"]','cmr07ifpj0000q8xdet31f7qd','cmr07ifuw0018q8xd0skvb1rt','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:11.482+00:00','2026-06-30T05:29:11.482+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/curry-hut-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/curry-hut-2.jpg"]','https://maps.google.com/?cid=16028796062406790108',NULL,NULL);
