INSERT INTO "Listing" VALUES('dhl-express','standard','cmr07igde008eq8xdmjt0jmhc','DHL Express','## Top Reviews
> "They called I think 12 different people to ask if I could mail chocolate. Just that part of the process took 30 minutes. They were ultimately able to help but it took forever and they didn’t seem to know what they were doing."
> **- Jack Styles (3/5/5)**

> "Amazing service by 2 ladies in the office. I spent a lot of time there having troubles with Amazon return and I was provided all the help. Very friendly and efficient services."
> **- Sybille Hardwick (5/5/5)**

> "Great trusted experience with the staff here, I had a parcel delivered to this store from Australia, I was contacted via WhatsApp to be advised it was delivered and the lady there is very friendly"
