INSERT INTO "Listing" VALUES('komaya-samui','standard','cmr07igts00f3q8xdydwb2232','Komaya Samui','## Top Reviews
> "A very cozy shop with a small but thoughtfully curated selection. The lovely owners made the shopping experience even more delightful. They’re also the only place on the island that carries Flatboy and Weber — a true hidden gem"
> **- Christina Shipunova (5/5/5)**

> "We have had the most wonderful experience with Mylene. Purchased a Weber Q which we were thrilled with. We recently had a slight problem and she’s given us the best customer service I’ve experienced. Clearly they stand by their product. Would completely recommend buying from here."
> **- Viila Sēcūra (5/5/5)**

> "After several days of waiting to see this shop fill up with beautiful home furnishings (Weber and Kamado barbecues; modern Fatboy garden accessories; a high-end selection of linens; glassware; and other accessories and decorations that can be hard to find on the island), I was thrilled to finally see it open! The layout is lovely, as are the staff and owners! I recommend it 1000%! 🙏🏻"
> **- Diane Barot (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/komaya-samui-1.jpg','062 728 2753','68/5, moi 1 Maenam, ตำบล แม่น้ำ อำเภอเกาะสมุย สุราษฎร์ธานี 84330, Thailand',NULL,NULL,5.0,0,0,0,NULL,NULL,'["Monday: 10:00 AM – 6:00 PM","Tuesday: 10:00 AM – 6:00 PM","Wednesday: 10:00 AM – 6:00 PM","Thursday: 10:00 AM – 6:00 PM","Friday: 10:00 AM – 6:00 PM","Saturday: 10:00 AM – 6:00 PM","Sunday: Closed"]','cmr07ifs5000eq8xdeu148200','cmr07ifte000sq8xdidrd81na','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.112+00:00','2026-06-30T05:29:12.112+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/komaya-samui-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/komaya-samui-2.jpg"]','https://maps.google.com/?cid=11406423811550845766',NULL,NULL);
