INSERT INTO "Listing" VALUES('kovani','standard','cmr07igtx00f5q8xd5vqpsuyg','Kovani','## Top Reviews
> "Best spot for a refreshment on the way to Nathon. Great yogurt ice-cream and the playground! Also can have a light meal here."
> **- Olga B (5/5/5)**

> "Just found our favorite frozen yogurt place on the island! The kids playground is incredible, with a tree house, obstacle courses, climb structure all made with natural materials. We had a great time enjoying the yummy fro-yo treats and playing games with the kids. ❤️"
> **- Miki Yu (5/5/5)**

> "Lovely wee cafe, bean bags to have a drink on. The lady was so lovely, couldn''t do enough for us. Food was delicious aswell, was hoping to try the frozen Yoghurt but I was so stuffed after my sandwich and milkshake. Air conditioning was lovely too. Cafe was so clean and there was loads on the menu to try. 🥰"
> **- Amanda Lavery (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/kovani-1.jpg','082 113 6050','57, 98, Tambon Ang Thong, Amphoe Ko Samui, Chang Wat Surat Thani 84140, Thailand',NULL,NULL,5.0,0,0,0,NULL,NULL,'["Monday: Closed","Tuesday: 9:00 AM – 6:00 PM","Wednesday: 9:00 AM – 6:00 PM","Thursday: 9:00 AM – 6:00 PM","Friday: 9:00 AM – 6:00 PM","Saturday: 9:00 AM – 6:00 PM","Sunday: 9:00 AM – 6:00 PM"]','cmr07ifwy001zq8xdppgaj2cs','cmr07ifxh0027q8xde6xqk8o6','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.117+00:00','2026-06-30T05:29:12.117+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/kovani-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/kovani-2.jpg"]','https://maps.google.com/?cid=7884275933532069404',NULL,NULL);
INSERT INTO "Listing" VALUES('krua-samui-restaurant','standard','cmr07igtz00f6q8xdlyi22cpm','Krua Samui Restaurant','## Top Reviews
> "The first thing that impressed me the most was the ambiance of the restaurant. The interior is beautifully designed with a warm and cozy atmosphere, offering both indoor air-conditioned seating and an outdoor area, allowing guests to choose according to their preference.  The menu is quite extensive, and the presentation of each dish is visually appealing and well-executed. In terms of taste, the food was excellent overall. We ordered sour curry with sea bass and young coconut shoots, prawns with tamarind sauce, an appetizer platter, shrimp omelette, and spicy stir-fried wild boar. The sour curry and prawns with tamarind sauce were particularly outstanding. However, the shrimp omelette was slightly too oily, and the wild boar dish was a bit too spicy for our taste.  As for the service, it may not yet reach a five-star standard, but it is still acceptable. The wine selection is somewhat limited; however, guests are allowed to bring their own, with a corkage fee applied.  Overall, it was a very good and impressive dining experience. The food was delicious, the atmosphere was excellent, and it is definitely a restaurant worth trying when visiting Koh Samui."
> **- Chaiyo Jiarachaikul (4/5/5)**

> "Very good food and service, something I have never tried before. The staff are very helpful and friendly. The Japanese Chef even came to say hi to our table. Highly recommend and I will definitely come back"
> **- Orapan Ratchawat Ratchawat (5/5/5)**

> "A cozy restaurant serving traditional Thai cuisine.  No fancy meal but authentic and tasty. Free welcome drink that was refreshing. Very attentive service. Nice decor. Instagrammable.  The pork however was too tough. Would not take this again."
> **- Martlet (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/krua-samui-restaurant-1.jpg','077 901 999','88 88, Tambon Bo Put, Amphoe Ko Samui, Chang Wat Surat Thani 84320, Thailand',NULL,NULL,4.7,0,0,0,NULL,'https://www.facebook.com/kruasamui/','["Monday: 3:00 – 11:00 PM","Tuesday: 3:00 – 11:00 PM","Wednesday: 3:00 – 11:00 PM","Thursday: 3:00 – 11:00 PM","Friday: 3:00 – 11:00 PM","Saturday: 3:00 – 11:00 PM","Sunday: 3:00 – 11:00 PM"]','cmr07ifpj0000q8xdet31f7qd','cmr07ifqw0003q8xdu2hrq6e7','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.119+00:00','2026-06-30T05:29:12.119+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/krua-samui-restaurant-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/krua-samui-restaurant-2.jpg"]','https://maps.google.com/?cid=10992031529899048205',NULL,NULL);
INSERT INTO "Listing" VALUES('kt-optic','standard','cmr07igu100f7q8xd8xou2h9a','KT Optic','## Top Reviews
> "Great optical shop! The staff here are genuinely friendly and helpful, and they have a beautiful selection of frames. They also repair glasses very quickly — I was impressed by how fast everything was done. Highly recommend!"
> **- Alyona A. (5/5/5)**

> "Excellent service and very friendly staff.  I needed original Maui Jim replacement lenses installed into my frame, and everything was done quickly, carefully, and professionally. It was clear that the staff handled the sunglasses with great attention and care.  What was especially appreciated was that they installed the lenses free of charge.  My sunglasses now look like new again. Thank you very much for the excellent service — highly recommended."
> **- Валентин Медведев (5/5/5)**

> "Had to do some service on my glasses. The staff were so helpful and friendly, and they fixed my glasses in 5 minutes. A very nice shop with good selection of eyewear"
> **- Kjetil N (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/kt-optic-1.jpg','077 961 672','โลตัสหาดละไม (สมุย) เลขที่ 131/12 ม.4 Tambon Maret, อ.เกาะสมุย Chang Wat Surat Thani 84130, Thailand',NULL,NULL,5.0,0,0,0,NULL,'http://www.ktoptic.com/','["Monday: 10:00 AM – 8:30 PM","Tuesday: 10:00 AM – 8:30 PM","Wednesday: 10:00 AM – 8:30 PM","Thursday: 10:00 AM – 8:30 PM","Friday: 10:00 AM – 8:30 PM","Saturday: 10:00 AM – 8:30 PM","Sunday: 10:00 AM – 8:30 PM"]','cmr07ifs5000eq8xdeu148200','cmr07ifrp0008q8xde8dk7pdm','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.121+00:00','2026-06-30T05:29:12.121+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/kt-optic-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/kt-optic-2.jpg"]','https://maps.google.com/?cid=7924725053371675305',NULL,NULL);
