INSERT INTO "Listing" VALUES('nakee-thai-massage-spa-choeng-mon','standard','cmr07ih7e00jeq8xd0126fylg','Nakee Thai Massage & Spa','## Top Reviews
> "For two weeks, my husband and I visited the Nakee salon. We have tried various massages, and the service is always very polite and attentive. Our backs said "
> **- Дарья Дьякова (5/5/5)**

> "This is definitely the next massage shop on the island. 100000%. 1 year already coming here and I recommend for anyone. My favorite therapists are Risa, Vas and Noy. But I didn’t try all therapists. I really think any person working in this shop is good: girls are always presentable, nice, highly highly professional! See you soon again! You are the best"
> **- Marina Pustokhod (5/5/5)**

> "I had an absolutely exceptional experience at this massage studio in Koh Samui. From the moment I walked in, the atmosphere was calm, clean, and incredibly welcoming. The entire space is designed to help you relax instantly — soft music, pleasant scents, and a very professional setup.  A special thank you goes to Vas, my massage therapist. She is truly outstanding at what she does. You can immediately tell that she has a deep understanding of the body and knows exactly how to release tension. Her technique is both strong and precise, yet very intuitive. She adjusted the pressure perfectly throughout the session and focused exactly on the areas that needed attention.  What really stood out to me was her attention to detail and genuine care. This was not just a standard massage — it felt personalized and thoughtfully executed from start to finish.  After the session, I felt completely relaxed, re-energized, and free of tension. It was honestly one of the best massages I’ve ever had.  If you’re in Koh Samui and looking for a high-quality, professional massage, I highly recommend this place — and especially Vas. I will definitely come back!"
> **- Kevin R. (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/nakee-thai-massage-spa-choeng-mon-1.jpg','083 126 7882','17 8, Tambon Bo Put, Amphoe Ko Samui, Chang Wat Surat Thani 84320, Thailand',NULL,NULL,4.9,0,0,0,NULL,'https://www.nakee.spa/online-reservation/book-appointment-at-bo-phut-beach/','["Monday: 10:00 AM – 11:00 PM","Tuesday: 10:00 AM – 11:00 PM","Wednesday: 10:00 AM – 11:00 PM","Thursday: 10:00 AM – 11:00 PM","Friday: 10:00 AM – 11:00 PM","Saturday: 10:00 AM – 11:00 PM","Sunday: 10:00 AM – 11:00 PM"]','cmr07ifst000mq8xdudn7dwk1','cmr07ifsv000nq8xdrwnu123q','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.602+00:00','2026-06-30T05:29:12.602+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/nakee-thai-massage-spa-choeng-mon-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/nakee-thai-massage-spa-choeng-mon-2.jpg"]','https://maps.google.com/?cid=7856497652224734851',NULL,NULL);
