> **- M.I. ten Bosch (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/napasai-1.jpg','077 429 200','65 10 Maenam Tambon Mae Nam, Amphoe Ko Samui, Chang Wat Surat Thani 84330, Thailand',NULL,NULL,4.8,0,0,0,NULL,'https://napasaisamui.com/',NULL,'cmr07ifv6001cq8xd5vsyfm44','cmr07ifso000kq8xdfe9gpaon','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.628+00:00','2026-06-30T05:29:12.628+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/napasai-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/napasai-2.jpg"]','https://maps.google.com/?cid=16149481287430848524',NULL,NULL);
