INSERT INTO "Listing" VALUES('pavilion-samui-villas-resort','standard','cmr07ihd200ljq8xddhbi08z0','Pavilion Samui Villas & Resort','## Top Reviews
> "Beautiful property.  Our 3rd visit, close to great shopping (night market next door) and restaurants (try Nana Tam down the street - we ate there 6 times!!)!! The property bar has excellent "
> **- Christine Tivas (5/5/5)**

> "Just stayed at this resort earlier this May, and it was such a private, lush, and cozy getaway. We stayed in a massive 2-story Family Pool Villa right by the beach, the views every morning and evening were incredibly relaxing. It comes with a private pool right out front and a jacuzzi on the second floor. I honestly didn''t want to go home! The room was super comfortable, the breakfast buffet had an amazing variety, and the staff took such great care of us. It’s absolutely worth the money. Highly recommended!"
> **- tanatorn tangkachaiyanant (5/5/5)**

> "Terrific stay at Pavilion and highly recommend.  The resort was very clean, and the staff went above and beyond.  Such hard working people too. Thank you for your amazing services. I especially loved the pools and beach. They had a security guard too so I had no worries of my stuff getting stolen while I was swimming. My only con was that one staff member who always poked so unhappy whenever I saw him, especially on the steak night event on Thursday’s. I had taken a look at the meats they had laid out on display but noticed the rib eye had run out so I said “no more ribeye”?  There were three staff members anroind the grill and he yelled out with an angry tone “Coming, wait!). I just looked at him and left to my table.  The rest of the time he avoided our table and instead the older gentleman Thandi helped us. He was amazing. So attentive and knew what we needed even before we did lol.  This hardworking man deserves a huge kudos. He made the stay more memorable. Thank you Thandi."
> **- Troy Delfino (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/pavilion-samui-villas-resort-1.jpg','077 424 030','124 Thanon Had Lamai, Tambon Maret, Amphoe Ko Samui, Chang Wat Surat Thani 84310, Thailand',NULL,NULL,4.5,0,0,0,NULL,'https://www.pavilionsamui.com/','["Monday: Open 24 hours","Tuesday: Open 24 hours","Wednesday: Open 24 hours","Thursday: Open 24 hours","Friday: Open 24 hours","Saturday: Open 24 hours","Sunday: Open 24 hours"]','cmr07ifv6001cq8xd5vsyfm44','cmr07ifrp0008q8xde8dk7pdm','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.806+00:00','2026-06-30T05:29:12.806+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/pavilion-samui-villas-resort-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/pavilion-samui-villas-resort-2.jpg"]','https://maps.google.com/?cid=1317692002939683795',NULL,NULL);
INSERT INTO "Listing" VALUES('pbiss-international-school','standard','cmr07ihd400lkq8xdlm3voxzb','PBISS International School','Discover PBISS International School, a premier for kids located in Chaweng Noi, Koh Samui. Find reviews, hours, and contact information.','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/pbiss-international-school-1.jpg','098 497 4479','6, 5, Tambon Bo Put, Amphoe Ko Samui, Chang Wat Surat Thani 84320, Thailand',NULL,NULL,0.0,0,0,0,NULL,'http://www.pbiss.ac.th/','["Monday: 8:00 AM – 5:00 PM","Tuesday: 8:00 AM – 5:00 PM","Wednesday: 8:00 AM – 5:00 PM","Thursday: 8:00 AM – 5:00 PM","Friday: 8:00 AM – 5:00 PM","Saturday: Closed","Sunday: Closed"]','cmr07ifwy001zq8xdppgaj2cs','cmr07ig5c0051q8xdykrbexft','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.808+00:00','2026-06-30T05:29:12.808+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/pbiss-international-school-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/pbiss-international-school-2.jpg"]','https://maps.google.com/?cid=13598282501569025378',NULL,NULL);
