INSERT INTO "Listing" VALUES('quick-fix-samui','standard','cmr07ihg100mrq8xdnxy4b943','Quick Fix Samui','## Top Reviews
> "⭐️⭐️⭐️⭐️⭐️ I contacted them to check and repair the air conditioning in our house on Samui, and I honestly couldn’t be happier with the service! They came the very next day, arrived on time, and worked super efficiently. The team was friendly, professional and they left everything spotless after finishing the job. All of our air cons are now working perfectly. Highly recommend this company to anyone on Samui looking for excellent air con service!"
> **- Lina Fee Petersen (5/5/5)**

> "You have repeatedly set appointment times and then abandoned them without any notice. By choosing this contractor, you are wasting a lot of our time. The lighting installation work was shoddy; the light fixtures and ceiling were damaged. I received a refund, but the work was never actually completed."
> **- Osamu Saito (2/5/5)**

> "We broke our glassdoor and the Quick Fix Samui Team came on the same day and fixes the glass very fast and with a fair price. The staff is also very kind and trustworthy. Conversation via whatsapp was super easy and quick respond! Can definetly recommend!"
> **- Michaela Strasser (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/quick-fix-samui-1.jpg','+66649963987','106, 51, ตำบล บ่อผุด อำเภอเกาะสมุย สุราษฎร์ธานี 84320, Thailand',NULL,NULL,4.6,0,0,0,NULL,'https://quickfix-samui.com/','["Monday: 9:00 AM – 5:00 PM","Tuesday: 9:00 AM – 5:00 PM","Wednesday: 9:00 AM – 5:00 PM","Thursday: 9:00 AM – 5:00 PM","Friday: 9:00 AM – 5:00 PM","Saturday: Closed","Sunday: Closed"]','cmr07ifrn0007q8xdq29pgizw','cmr07ifqw0003q8xdu2hrq6e7','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.913+00:00','2026-06-30T05:29:12.913+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/quick-fix-samui-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/quick-fix-samui-2.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/quick-fix-samui-3.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/quick-fix-samui-4.jpg"]','https://maps.google.com/?cid=16361356020873401927',NULL,NULL);
INSERT INTO "Listing" VALUES('rajapruek-samui-resort','standard','cmr07ihg300msq8xd6yjcbff0','Rajapruek Samui Resort','## Top Reviews
> "I didn''t stay here, but I attended a training course. The seminar room was clean and the air conditioning was very cool. There were enough restrooms, and they were clean and smelled nice. There are two large swimming pools. From what I saw, the accommodations are divided into several zones. They look nice, especially the section near the beach. It seems quiet, private, and has a great atmosphere. The beach view is peaceful. The staff were friendly and provided excellent service, and the food was delicious. I recommend the green curry."
> **- muri gui (5/5/5)**

> "We loved our stay here. The location is so perfect on a beautiful quiet beach. We stayed in a garden villa and literally rolled out of bed and walked one min to the beach beds! The place has its own special charm with Thai motifs and sculptures everywhere. It''s certainly a bit older, and if they invested a little bit in refreshing the hotel it could go a long way. But we were very happy with how it is now :)"
> **- Jehana Vazifdar (5/5/5)**

> "Really lovely (older) place with plenty of charm. We stayed in one of the beach-side villas, which was delightful! The area is much quieter than the East coast, which we really appreciated. Only negative was the breakfast wasn''t anything special!"
> **- paulkeb (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/rajapruek-samui-resort-1.jpg','077 485 780','95 5, Tambon Lipa Noi, Amphoe Ko Samui, Chang Wat Surat Thani 84140, Thailand',NULL,NULL,4.2,0,0,0,NULL,'http://www.rajaprueksamuiresort.com/',NULL,'cmr07ifv6001cq8xd5vsyfm44','cmr07ifsb000gq8xdch1ib0om','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:12.915+00:00','2026-06-30T05:29:12.915+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/rajapruek-samui-resort-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/rajapruek-samui-resort-2.jpg"]','https://maps.google.com/?cid=16475831127442712283',NULL,NULL);
