INSERT INTO "Listing" VALUES('saii-beach-club','standard','cmr07ihj000nuq8xdjmpsfb01','SAii Beach Club','## Top Reviews
> "Had a fantastic stay at SAii Koh Samui Villas beautiful views of the ocean overlooking the pool and bar area. Friendly and very accommodating staff - special mention for our barman Aek who provided such personal and kind service. Individual pools for each Villa was a real bonus xo lovely food. Ava arranged our day trip to Anthong Park which was a great day out - thank you for your hospitality xo"
