INSERT INTO "Listing" VALUES('the-privilege-hotel','standard','cmr07ii5h00woq8xdemg6gqd0','The Privilege Hotel','## Top Reviews
> "Great hotel with very friendly staff and central location. We upgraded to the villas and got a pool that was shared with other villas but was almost always empty so we had it to ourselves. The small private beach is nice and the hotel restaurant is right on it. Overall great stay"
> **- Maya Gal (5/5/5)**

> "If you are looking for a cool place that looks good in photos, then this is probably the spot for you. The bed was good and the room was nice, but really not much to offer in terms of service quality and amenities. There were a few not so friendly staff, and there seemed to be a new issue every hour we spent (there were also a few great and friendly staff, but the good usually gets hung down by the not so good).  The food and drinks were ok, but weren’t really worth sitting around for."
> **- Zachary Silva (3/5/5)**

> "Pros +location +nice infinity pool (long and narrow) +i really enjoyed opening my sliding glass door am being right on the pool deck.  Cons -music runs until 10pm, my mother in law didn’t love that. -not a lot of surfaces in rooms, I.e. no nightstands, no suitcase stand, so belongings had to be on floor. Good value, I would return."
> **- Pareen “PareenK.” Dholoo (5/5/5)**','https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/the-privilege-hotel-1.jpg','077 954 094','5, Bangrak Beach T, 1, Tambon Bo Put, Amphoe Ko Samui, Chang Wat Surat Thani 84320, Thailand',NULL,NULL,4.3,0,0,0,NULL,'https://advance-booking.com/the-privilege-hotel-ezra-beach-club/','["Monday: Open 24 hours","Tuesday: Open 24 hours","Wednesday: Open 24 hours","Thursday: Open 24 hours","Friday: Open 24 hours","Saturday: Open 24 hours","Sunday: Open 24 hours"]','cmr07ifv6001cq8xd5vsyfm44','cmr07ifrv000aq8xdn6zpp33d','cmqyzwjmd0000iuxdbv41llnf','2026-06-30T05:29:13.829+00:00','2026-06-30T05:29:13.829+00:00','["https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/the-privilege-hotel-1.jpg","https://pub-3433478e81804444ae052b8316ad0d83.r2.dev/images/businesses/the-privilege-hotel-2.jpg"]','https://maps.google.com/?cid=17562357606833473475',NULL,NULL);
