INSERT INTO "Listing" VALUES('yoyo-bar','standard','cmr07iig6010mq8xdxanuj5tx','YOYO Bar','## Top Reviews
> "Haven''t tried everything from the menu yet, but can confirm that burgers and meatballs are really good. Staff and owners are very nice and warmly welcome every time even tho I''m a single lady here. Good music, awesome vibes ❤. Best Long Island Ice Tea I have ever tasted 🤩!"
